eval(String(source.loginUrl));
var exploreUrl = [];
var Sort = `{{get('sort',Get('q'))}}`;
var Filters = `{{get('filters',Get('r'))}}`;
var Filters1 = `{{get('filters1',Get('s'))}}`;
function explore(e, f, g) {
    if (g=='类别') {
        style = `${e}::${f}\n`;
    } else if (g=='收藏') {
        style = `${e}::@js:\`${f}\`\n`;
    } else if (g=='分类') {
        style = `${e}::@js:\`${f}?page={{page}}&filters=${Filters}&sort=${Sort}\`\n`;
    } else if (g=='日本') {
        style = `${e}::@js:\`${f}?page={{page}}&filters=${Filters}\`\n`;
    } else {//女优
        style = `${e}::@js:\`${f}?page={{page}}&filters=${Filters}&sort=${Sort}\`\n`;
    }
    return style;
}

sc = Map('收藏：');
scs = sc !== '' ? sc.split(",") : [];
if (scs.length > 0) {
    scs.forEach((sc) => {
        let scHref = `{{Get('url')}}/cn/search/${sc}?page={{page}}&filters=${Filters1}&sort=${Sort}`;
        exploreUrl.push(explore(sc, scHref, '收藏'));
    });
}

