href = window.location.href;
if(href.search(/#/) == -1) {
  author = $$(".authorname");
  html = "";
  node = $$(".read");

  // 构建HTML头部
  html = `
    <!DOCTYPE html>
    <html>
    <head>
      <meta charset="UTF-8">
      <meta name="viewport" content="width=device-width, initial-scale=1.0">
      <style>
        body {
          font-family: Arial, sans-serif;
          line-height: 1.6;
          max-width: 800px;
          margin: 0 auto;
          padding: 20px;
          color: #333;
          background: #fff;
        }
