         #msgsubject {
      font-size: 20px;
      font-weight: bold;
      margin-bottom: 20px;
      padding-bottom: 10px;
      border-bottom: 1px solid #eee;
    }
        .author {
          font-size: 14px;
          color: #666;
          margin: 15px 0 5px 0;
          padding: 5px 0;
        }
        .author .no {
          color: #ff6b6b;
          font-weight: bold;
          margin-right: 5px;
        }
        .read {
          margin: 10px 0 25px 0;
          padding: 15px;
          background-color: #f9f9f9;
          border-radius: 5px;
          border-left: 3px solid #ff6b6b;
        }
        .replybodyinner {
          white-space: pre-wrap;
          word-wrap: break-word;
          line-height: 1.5;
        }
        hr {
          border: 0;
          height: 1px;
          background-color: #eee;
          margin: 20px 0;
        }

      </style>
    </head>
    <body>
  `;

  // 添加顶部分页器
  page = $$("#pager_top")[0] ? $$("#pager_top")[0].outerHTML : "";
  if(page) {
    html += `${page}`;
  }
nickname = $$(".nickname")
  // 添加主题标题（增加额外间距）
  zhu = $("#msgsubject") ? $("#msgsubject").innerText : "";
  html += `<div id="msgsubject">${zhu}</div>`;

  // 构建内容部分（增加首条内容额外间距）
  for(i = 0; i < author.length; i++) {
    a = author[i].innerText.replace(/加书签|举报/g, '').replace(/☆☆☆/g, '');
    // 提取编号和作者信息
    const noMatch = a.match(/№(\d+)/);
    const no = noMatch ? noMatch[0] : '';
    const rest = a.match(/\d+-\d+-\d+ \d+:\d+:\d+/)?.[0]??""

    // 第一条内容增加额外上边距

    html += `
      <div class="author">
        <span class="no">${no}</span>${nickname[i].innerText} | ${rest}
      </div>
      <div class="read">${node[i].innerHTML}</div>
      ${i < author.length - 1 ? '<hr>' : ''}
    `;
  }

  // 添加底部分页器
  if(page) {
    html += `<div class="pager">${page}</div>`;
  }

  // 闭合HTML标签
  html += `</body></html>`;

  // 替换整个页面内容
  document.documentElement.innerHTML = html;
}

